mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM wms_outbound_order_item i
    WHERE i.warehouse_id = #{warehouseId}
      AND EXISTS (
            SELECT 1
            FROM wms_outbound_order o
            WHERE o.id = i.outbound_id
              AND o.deleted = 0
              AND o.status IN
              #{status}
      )
)

SELECT EXISTS (
    SELECT 1
    FROM wms_outbound_order_item
    WHERE warehouse_id = #{warehouseId}
)

SELECT EXISTS (
    SELECT 1
    FROM wms_outbound_order_item i
    WHERE i.location_id = #{locationId}
      AND EXISTS (
            SELECT 1
            FROM wms_outbound_order o
            WHERE o.id = i.outbound_id
              AND o.deleted = 0
              AND o.status IN
              #{status}
      )
)

SELECT EXISTS (
    SELECT 1
    FROM wms_outbound_order_item
    WHERE location_id = #{locationId}
)
